/**
 * Tests for lifecycle/goal-budget-guard (M140 G5 #1791)
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { existsSync, mkdirSync, mkdtempSync, readFileSync, rmSync, writeFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

import { goalBudgetGuard, sumSessionUsage } from '../../lifecycle/goal-budget-guard.js';
import type { HookInput } from '../../types.js';
import { createTestContext } from '../fixtures/test-context.js';

let tmp: string;
const BRAKE_REL = join('.claude', 'state', 'goal-budget-tripped.json');

beforeEach(() => {
  tmp = mkdtempSync(join(tmpdir(), 'goal-budget-'));
  delete process.env.ORK_GOAL_MAX_TURNS_PER_SESSION;
  delete process.env.ORK_GOAL_MAX_TOKENS_PER_SESSION;
});

afterEach(() => {
  rmSync(tmp, { recursive: true, force: true });
  delete process.env.ORK_GOAL_MAX_TURNS_PER_SESSION;
  delete process.env.ORK_GOAL_MAX_TOKENS_PER_SESSION;
});

function writeHistory(lines: object[]): void {
  const dir = join(tmp, '.claude', 'state');
  mkdirSync(dir, { recursive: true });
  writeFileSync(
    join(dir, 'goal-history.jsonl'),
    `${lines.map(l => JSON.stringify(l)).join('\n')}\n`,
  );
}

describe('sumSessionUsage', () => {
  it('sums turns + tokens only for closed entries matching sessionId', () => {
    const raw = [
      { session_id: 'A', ended_at: 't', turn_count: 5, ended_token_estimate: 1000 },
      { session_id: 'A', ended_at: null, turn_count: 9 },               // skipped (open)
      { session_id: 'B', ended_at: 't', turn_count: 100 },              // skipped (wrong session)
      { session_id: 'A', ended_at: 't', turn_count: 3, ended_token_estimate: 500 },
    ].map(o => JSON.stringify(o)).join('\n');
    expect(sumSessionUsage(raw, 'A')).toEqual({ turns: 8, tokens: 1500 });
  });

  it('returns zero totals when no matching entries', () => {
    expect(sumSessionUsage('', 'X')).toEqual({ turns: 0, tokens: 0 });
  });
});

describe('goalBudgetGuard hook', () => {
  it('does nothing and returns silent success when under budget', () => {
    writeHistory([
      { session_id: 'sess-A', ended_at: 't', turn_count: 5, ended_token_estimate: 1000 },
    ]);
    const ctx = createTestContext({ projectDir: tmp, sessionId: 'sess-A' });
    const input: HookInput = { tool_name: '', session_id: 'sess-A', tool_input: {} };

    const result = goalBudgetGuard(input, ctx);
    expect(result).toEqual({ continue: true, suppressOutput: true });
    expect(existsSync(join(tmp, BRAKE_REL))).toBe(false);
  });

  it('writes brake file when turns_cap breached', () => {
    process.env.ORK_GOAL_MAX_TURNS_PER_SESSION = '10';
    writeHistory([
      { session_id: 'sess-A', ended_at: 't', turn_count: 11, ended_token_estimate: 100 },
    ]);
    const ctx = createTestContext({ projectDir: tmp, sessionId: 'sess-A' });
    const input: HookInput = { tool_name: '', session_id: 'sess-A', tool_input: {} };

    const result = goalBudgetGuard(input, ctx);
    expect(result).toEqual({ continue: true, suppressOutput: true });

    const brake = JSON.parse(readFileSync(join(tmp, BRAKE_REL), 'utf8'));
    expect(brake.reason).toBe('turns_cap');
    expect(brake.turns).toBe(11);
    expect(brake.session_id).toBe('sess-A');
    expect(brake.tripped_at).toBeTruthy();
  });

  it('writes brake file when tokens_cap breached', () => {
    process.env.ORK_GOAL_MAX_TOKENS_PER_SESSION = '5000';
    writeHistory([
      { session_id: 'sess-A', ended_at: 't', turn_count: 2, ended_token_estimate: 6000 },
    ]);
    const ctx = createTestContext({ projectDir: tmp, sessionId: 'sess-A' });
    const input: HookInput = { tool_name: '', session_id: 'sess-A', tool_input: {} };

    goalBudgetGuard(input, ctx);
    const brake = JSON.parse(readFileSync(join(tmp, BRAKE_REL), 'utf8'));
    expect(brake.reason).toBe('tokens_cap');
    expect(brake.tokens).toBe(6000);
  });

  it('returns silent success and writes no brake when history is missing', () => {
    const ctx = createTestContext({ projectDir: tmp, sessionId: 'sess-X' });
    const input: HookInput = { tool_name: '', session_id: 'sess-X', tool_input: {} };
    const result = goalBudgetGuard(input, ctx);
    expect(result).toEqual({ continue: true, suppressOutput: true });
    expect(existsSync(join(tmp, BRAKE_REL))).toBe(false);
  });
});
